[menu, activator].forEach(el => {
  el.addEventListener('blur', () => {
    setTimeout(() => {
      if (!menu.matches(':focus-within') && !document.activeElement.isSameNode(activator)) {
        closeMenu();
      }
    }, 0);
  });
});

